// 强制覆盖存档函数为 localStorage 实现
window.setCookie = function(name, value) {
    if (value === undefined || value === null) {
        localStorage.removeItem(name);
    } else {
        localStorage.setItem(name, String(value));
        console.log("存档保存: " + name + " = " + value);
    }
};
window.getCookie = function(name) {
    var val = localStorage.getItem(name);
    console.log("读取存档: " + name + " = " + (val !== null ? val : "null"));
    return val;
};
window.delCookie = function(name) {
    localStorage.removeItem(name);
    console.log("删除存档: " + name);
};

// 本地化成就请求
(function() {
    // 保存原函数（如果需要可保留，但直接覆盖即可）
    var originalPostAchievement = window.post_achievement;
    
    window.post_achievement = function(action, successCallback, errorCallback) {
        // 根据 action 参数决定加载哪个 JSON 文件
        // 'LOAD' 或 'GET' → 成就数据（achievement.json）
        // 其他（如 'SEND'）→ 奖励状态（achievement2.json）
        var url = (action === 'LOAD' || action === 'GET') 
            ? 'utils/achievementDurandal.json' 
            : 'utils/achievementDurandal2.json';
        
        fetch(url)
            .then(function(response) {
                if (!response.ok) {
                    throw new Error('HTTP error ' + response.status);
                }
                return response.json();
            })
            .then(function(data) {
                window.ajax_answer_achievement = data;
                if (successCallback) successCallback();
            })
            .catch(function(err) {
                console.error('读取本地成就文件失败: ' + url, err);
                window.ajax_answer_achievement = null;
                if (errorCallback) errorCallback();
            });
    };
})();